import sys

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def findMinAndMax(self, root: TreeNode) -> list[int]:
        if not root:
            return []
        min_val = root.val
        max_val = root.val
        stack = [root]
        while stack:
            node = stack.pop()
            if node.val < min_val:
                min_val = node.val
            if node.val > max_val:
                max_val = node.val
            if node.left:
                stack.append(node.left)
            if node.right:
                stack.append(node.right)
        return [min_val, max_val]

if __name__ == '__main__':
    try:
        n = int(sys.stdin.readline().strip())
        nodes = [None] * n
        for i in range(n):
            vals = list(map(int, sys.stdin.readline().strip().split()))
            node = TreeNode(vals[0])
            nodes[i] = node
            left, right = vals[1], vals[2]
            if left != -1:
                node.left = nodes[left]
            if right != -1:
                node.right = nodes[right]
        root = nodes[0]
        sol = Solution()
        ans = sol.findMinAndMax(root)
        print(' '.join(map(str, ans)))
    except Exception as e:
        pass

