#include <numeric>
#include <iostream>
#include <vector>
#include <stack>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<int> findMinAndMax(TreeNode* root) {
        if (!root) return {};
        int min_val = root->val;
        int max_val = root->val;
        stack<TreeNode*> st;
        st.push(root);
        while (!st.empty()) {
            TreeNode* node = st.top(); st.pop();
            if (node->val < min_val) min_val = node->val;
            if (node->val > max_val) max_val = node->val;
            if (node->right) st.push(node->right);
            if (node->left) st.push(node->left);
        }
        return {min_val, max_val};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; i++) {
        int val, left, right;
        cin >> val >> left >> right;
        nodes[i] = new TreeNode(val);
        if (left != -1) nodes[i]->left = nodes[left];
        if (right != -1) nodes[i]->right = nodes[right];
    }
    TreeNode* root = nodes[0];
    Solution sol;
    vector<int> ans = sol.findMinAndMax(root);
    cout << ans[0] << " " << ans[1] << "\n";
    return 0;
}
